import android.content.Context;
import android.content.SharedPreferences;
import android.util.Log;

public class LoginManager {
    private static final String TAG = "LoginManager";

    private SharedPreferences sharedPrefs;

    public LoginManager(Context context) {
        this.sharedPrefs = context.getSharedPreferences("login_credentials", Context.MODE_PRIVATE);
    }

    public void saveCredentials(String email, String authToken) {
        SharedPreferences.Editor editor = sharedPrefs.edit();
        editor.putString("email", email);
        editor.putString("auth_token", authToken);
        editor.apply();
    }

    public boolean isLoggedIn() {
        return sharedPrefs.contains("email") && sharedPrefs.contains("auth_token");
    }

    public String getEmail() {
        return sharedPrefs.getString("email", null);
    }

    public String getAuthToken() {
        return sharedPrefs.getString("auth_token", null);
    }
}